Javascript.validate:
var val = Services.getValue(AQFilingFee.dataBinding);
var err = validateCurrencyValue(val, 999999.99, true);
if( null == err)
{	var fmVal = WPU.formatToTwoDP(val);
	Services.setValue(AQFilingFee.dataBinding, fmVal);
}
return err;

