function DefaultCurrency148() {}
DefaultCurrency148.dataBinding = "/ds/EnterVariableData/curr1";
DefaultCurrency148.tabIndex = -1;
DefaultCurrency148.maxLength = 1;
DefaultCurrency148.isReadOnly = function(){return true;}
DefaultCurrency148.isTemporary = function(){return true;}
DefaultCurrency148.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency148.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
